fn gcd(mut m: u64, mut n: u64) -> u64 {
    if m == 0 && n == 0 {
        panic!("gcd(0, 0) is undefined");
    }
    while m != 0 && n != 0 {
        if m > n {
            m %= n;
        } else {
            n %= m;
        }
    }
    if m == 0 {
        n
    } else {
